import Link from "next/link";
import { Section } from "./section";

export type CareerEntry = {
  role: string;
  company: string;
  year: string;
  isCurrent?: boolean;
};

export type AboutSectionProps = {
  /** Short intro label above the narrative */
  introLabel?: string;
  /** Big statement lines (one per item, displayed as headlines) */
  narrative: string[];
  /** Career timeline entries */
  career: CareerEntry[];
  /** CTA line (before the link) */
  ctaLine?: string;
  /** CTA link text */
  ctaLinkText?: string;
  /** Email for say hello (mailto) */
  contactEmail?: string;
  /** Closing lines below CTA */
  closingLines?: string[];
};

const defaultIntroLabel = "A bit about who I am…";
const defaultCtaLine =
  "I'm always looking to learn, grow, and teach. If that aligns with you—please,";
const defaultCtaLinkText = "say hello!";
const defaultClosingLines = ["Thanks for coming by.", "See you around."];

export function AboutSection({
  introLabel = defaultIntroLabel,
  narrative,
  career,
  ctaLine = defaultCtaLine,
  ctaLinkText = defaultCtaLinkText,
  contactEmail,
  closingLines = defaultClosingLines,
}: AboutSectionProps) {
  const mailto = contactEmail ? `mailto:${contactEmail}` : "#";

  return (
    <Section id="about" title="About" subtitle={introLabel}>
      <div className="space-y-10 sm:space-y-14">
        {/* Narrative: big statement lines */}
        <div className="space-y-6 sm:space-y-8">
          {narrative.map((line, i) => (
            <p
              key={i}
              className="text-xl font-extralight leading-[1.35] tracking-tight text-zinc-50 sm:text-2xl"
              style={{ fontFamily: "var(--font-crimson)" }}
            >
              {line}
            </p>
          ))}
        </div>

        {/* Career timeline */}
        <div>
          <p
            className="mb-6 text-lg font-extralight text-zinc-400/90 sm:text-xl"
            style={{ fontFamily: "var(--font-crimson)" }}
          >
            Though I&apos;ve been working for a while, here&apos;s a quick glance
            at the last few years.
          </p>
          <div className="grid gap-3 sm:grid-cols-2">
            {career.map((entry, i) => (
              <div
                key={i}
                className="group flex flex-col gap-1 rounded-[18px] border border-white/10 bg-zinc-950/70 px-5 py-4 shadow-[0_18px_60px_rgba(0,0,0,0.5)] transition-colors hover:bg-zinc-900/60 hover:border-white/15"
              >
                <span className="text-[0.65rem] font-medium tracking-[0.14em] text-zinc-400">
                  {entry.year}
                  {entry.isCurrent ? " · Current" : ""}
                </span>
                <span
                  className="text-base font-semibold text-zinc-100 sm:text-lg"
                  style={{ fontFamily: "var(--font-crimson)" }}
                >
                  {entry.role}
                </span>
                <span className="text-sm text-zinc-300/90">{entry.company}</span>
              </div>
            ))}
          </div>
        </div>

        {/* CTA */}
        <div className="space-y-6 border-t border-white/5 pt-10">
          <p
            className="text-xl font-extralight leading-[1.35] tracking-tight text-zinc-50 sm:text-2xl"
            style={{ fontFamily: "var(--font-crimson)" }}
          >
            {ctaLine}{" "}
            <Link
              href={mailto}
              className="underline decoration-zinc-500 underline-offset-4 transition-colors hover:text-zinc-100 hover:decoration-zinc-400"
            >
              {ctaLinkText}
            </Link>
          </p>
          <div className="flex flex-col gap-1 text-sm text-zinc-400">
            {closingLines.map((line, i) => (
              <span key={i}>{line}</span>
            ))}
          </div>
        </div>
      </div>
    </Section>
  );
}
